"""Frontend assets. COURSE_TMPL is the tokenized course app;
PLAYGROUND_SECTION is the generic backend-driven console, inserted
only for packs that stipulate a playground."""

COURSE_TMPL = '<!doctype html>\n<html lang="en"><head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width,initial-scale=1">\n<title>%%CODE%% &middot; WGU Study Hub</title>\n<link rel="icon" href=\'data:image/svg+xml,%3Csvg xmlns=\'http://www.w3.org/2000/svg\' viewBox=\'0 0 32 32\'%3E%3Crect width=\'32\' height=\'32\' rx=\'7\' fill=\'%23003057\'/%3E%3Ccircle cx=\'11\' cy=\'13\' r=\'6\' fill=\'%23FFB81C\'/%3E%3Ccircle cx=\'21\' cy=\'13\' r=\'6\' fill=\'%23FFB81C\'/%3E%3Ccircle cx=\'11\' cy=\'13\' r=\'2.6\' fill=\'%23001527\'/%3E%3Ccircle cx=\'21\' cy=\'13\' r=\'2.6\' fill=\'%23001527\'/%3E%3Cpath d=\'M16 16l-3.2 4.2 3.2 4.2 3.2-4.2z\' fill=\'%23FFB81C\'/%3E%3C/svg%3E\'>\n<link rel="stylesheet" href="/app.css">\n</head><body>\n<header class="topbar"><div class="wrap">\n  <a class="brand" href="/">\n<svg class="owl" viewBox="0 0 120 126" aria-hidden="true">\n  <path d="M30 36 L40 14 L50 33 Z" fill="#0A3B66"/>\n  <path d="M90 36 L80 14 L70 33 Z" fill="#0A3B66"/>\n  <ellipse cx="60" cy="74" rx="40" ry="46" fill="#0A3B66"/>\n  <ellipse cx="60" cy="60" rx="35" ry="31" fill="#0E4A7B"/>\n  <ellipse cx="60" cy="98" rx="21" ry="15" fill="#12588F"/>\n  <circle cx="45" cy="58" r="14" fill="#FFB81C"/>\n  <circle cx="75" cy="58" r="14" fill="#FFB81C"/>\n  <circle cx="45" cy="58" r="6" fill="#001527"/>\n  <circle cx="75" cy="58" r="6" fill="#001527"/>\n  <rect class="lid" x="31" y="44" width="28" height="28" rx="14" fill="#0E4A7B"/>\n  <rect class="lid" x="61" y="44" width="28" height="28" rx="14" fill="#0E4A7B"/>\n  <path d="M60 66 L53 75 L60 85 L67 75 Z" fill="#FFB81C"/>\n</svg> WGU Study Hub</a>\n  <span class="crumb">/ %%CODE%% &middot; %%NAME%%</span>\n  <span class="spacer"></span>\n  <span class="badge-cli">%%BADGE%%</span>\n</div></header>\n<nav class="tabs"><div class="wrap">\n%%TABS%%\n</div></nav>\n\n<main class="wrap">\n\n%%PLAYGROUND_SECTION%%\n\n<section id="drill" class="hidden">\n  <div class="panel" id="drillsetup">\n    <h3>Exam drill</h3>\n    <p class="sub">Multiple choice, like the real OA. Weighted by the practice-test\n      blueprint and by what you\'ve been missing.</p>\n    <div class="row">\n      <label class="sub" style="margin:0" for="qn">questions</label>\n      <select id="qn"><option>5</option><option selected>10</option>\n        <option>15</option><option>20</option><option>30</option></select>\n      <label class="sub" style="margin:0" for="qtopic">focus</label>\n      <select id="qtopic">%%TOPIC_OPTIONS%%\n      </select>\n      <button class="btn gold" id="qstart">Start drill</button>\n    </div>\n  </div>\n  <div class="panel hidden" id="quizarea"></div>\n</section>\n\n%%SQLDRILL_SECTION%%\n\n<section id="mastery" class="hidden">\n  <div class="panel">\n    <div class="row" style="justify-content:space-between">\n      <div><h3>Mastery map</h3>\n        <p class="sub">Shared with the terminal version &mdash; every answer,\n        either place, moves these bars and re-weights your next drill.</p></div>\n      <div class="row">\n        <button class="btn ghost" id="mreload">Refresh</button>\n        <button class="btn ghost" id="mreset">Reset history</button>\n      </div>\n    </div>\n    <div id="masterybody"></div>\n  </div>\n</section>\n\n<section id="guide" class="hidden">\n  <div class="panel">%%GUIDE_BODY%%</div>\n</section>\n\n</main>\n<script>\n"use strict";\nconst $ = (s, el) => (el || document).querySelector(s);\nconst $$ = (s, el) => Array.from((el || document).querySelectorAll(s));\nconst esc = s => String(s).replace(/[&<>"]/g,\n  c => ({"&":"&amp;","<":"&lt;",">":"&gt;",\'"\':"&quot;"}[c]));\nconst BASE = "%%BASE%%";\nasync function api(path, body) {\n  if (path.startsWith("/api/")) path = BASE + path;\n  const r = await fetch(path, body === undefined ? {} :\n    {method:"POST", headers:{"Content-Type":"application/json"},\n     body: JSON.stringify(body)});\n  return r.json();\n}\nfunction tableHTML(headers, rows, total, truncated) {\n  let h = \'<div class="tablewrap"><table class="res"><thead><tr>\';\n  headers.forEach(x => h += "<th>" + esc(x) + "</th>");\n  h += "</tr></thead><tbody>";\n  rows.forEach(r => {\n    h += "<tr>";\n    r.forEach(v => h += "<td>" + (v === null ?\n      \'<span class="null">NULL</span>\' : esc(v)) + "</td>");\n    h += "</tr>";\n  });\n  h += "</tbody></table></div>";\n  let meta = total + " row" + (total === 1 ? "" : "s") + " in set";\n  if (truncated) meta += " (showing first " + rows.length + ")";\n  return h + \'<div class="meta">\' + meta + "</div>";\n}\n\n/* ---------- tabs ---------- */\nfunction openTab(name) {\n  $$(".tab").forEach(b => b.classList.toggle("on", b.dataset.tab === name));\n  $$("section[id]").forEach(sec =>\n    sec.classList.toggle("hidden", sec.id !== name));\n  if (name === "mastery") loadMastery();\n  history.replaceState(null, "", "#" + name);\n}\n$$(".tab").forEach(b => b.addEventListener("click", () => openTab(b.dataset.tab)));\n\n/* ---------- playground (generic, backend-driven) ---------- */\nconst bindEl = (sel, ev, fn) => { const el = $(sel); if (el) el.addEventListener(ev, fn); };\nfunction renderBlocks(payload) {\n  const box = $("#results");\n  if (!box) return;\n  box.innerHTML = "";\n  (payload.blocks || []).forEach(b => {\n    const div = document.createElement("div");\n    div.className = "result panel";\n    let h = "";\n    if (b.kind === "table") h += tableHTML(b.headers, b.rows, b.total, b.truncated);\n    else if (b.kind === "error") h += \'<div class="errmsg">\' + esc(b.text) + "</div>";\n    else if (b.kind === "ok") h += \'<div class="okmsg">\' + esc(b.text) + "</div>";\n    else h += \'<pre class="pgout">\' + esc(b.text) + "</pre>";\n    (b.notes || []).forEach(n => h += \'<div class="note">\' + esc(n) + "</div>");\n    div.innerHTML = h;\n    box.appendChild(div);\n  });\n  (payload.notes || []).forEach(n => {\n    const div = document.createElement("div");\n    div.className = "result panel";\n    div.innerHTML = \'<div class="note">\' + esc(n) + "</div>";\n    box.appendChild(div);\n  });\n  if (!box.childNodes.length)\n    box.innerHTML = \'<div class="result panel empty">Nothing to run yet.</div>\';\n}\nasync function loadSide() {\n  if (!$("#playground")) return;\n  const d = await api("/api/side");\n  const sp = $("#sidepane"), play = $(".play");\n  if (!d.sidebar) {\n    if (sp) sp.style.display = "none";\n    if (play) play.classList.add("noside");\n  } else {\n    $("#sidetitle").textContent = d.sidebar.title || "";\n    $("#sidesub").innerHTML = d.sidebar.sub || "";\n    $("#sidelist").innerHTML = (d.sidebar.groups || []).map(g => {\n      const chips = (g.items || []).map(it =>\n        \'<span class="tchip"><button data-run="\' + esc(it.run) +\n        \'" title="\' + esc(it.title || "") + \'">\' + esc(it.label) + "</button>" +\n        (it.alt_run ? \'<button class="sch" data-run="\' + esc(it.alt_run) +\n          \'" title="\' + esc(it.alt_title || "") + \'">i</button>\' : "") +\n        "</span>").join("");\n      const reset = g.reset ? \' &middot; <button class="linkish" data-reset="\' +\n        esc(g.name) + \'">reset</button>\' : "";\n      return \'<div class="dbgroup"><div class="dbname">\' +\n        \'<span class="dot\' + (g.on ? " on" : "") + \'"></span>\' + esc(g.name) +\n        \'</div><div class="dbdesc">\' + esc(g.desc || "") + reset +\n        \'</div><div class="tchips">\' + chips + "</div></div>";\n    }).join("");\n    const ra = $("#resetall");\n    if (ra && d.sidebar.reset_all) {\n      ra.textContent = d.sidebar.reset_all;\n      ra.classList.remove("hidden");\n    }\n  }\n  const sel = $("#pgsel");\n  if (sel && d.selector) {\n    sel.dataset.tmpl = d.selector.run_template || "";\n    const lb = $("#pgsellbl");\n    if (lb) { lb.textContent = d.selector.label || ""; lb.classList.remove("hidden"); }\n    sel.classList.remove("hidden");\n    sel.innerHTML = (d.selector.options || []).map(o =>\n      "<option" + (o === d.selector.current ? " selected" : "") + ">" +\n      esc(o) + "</option>").join("");\n  }\n}\nasync function runCode(src) {\n  const sd = $("#pgstdin");\n  const d = await api("/api/run", {source: src, stdin: sd ? sd.value : ""});\n  renderBlocks(d);\n  loadSide();\n}\nbindEl("#runbtn", "click", () => runCode($("#pgbox").value));\nbindEl("#pgbox", "keydown", e => {\n  if ((e.ctrlKey || e.metaKey) && e.key === "Enter") {\n    e.preventDefault(); runCode($("#pgbox").value);\n  }\n});\nbindEl("#pgsel", "change", e => {\n  const t = e.target.dataset.tmpl || "";\n  if (t) runCode(t.split("{value}").join(e.target.value));\n});\nbindEl("#sidelist", "click", e => {\n  const b = e.target.closest("button");\n  if (!b) return;\n  if (b.dataset.reset !== undefined) {\n    api("/api/reset", {target: b.dataset.reset}).then(d => {\n      renderBlocks({blocks: [{kind: "ok", text: d.message || "Restored."}]});\n      loadSide();\n    });\n    return;\n  }\n  if (b.dataset.run !== undefined) {\n    const pb = $("#pgbox");\n    if (pb) pb.value = b.dataset.run;\n    runCode(b.dataset.run);\n  }\n});\nbindEl("#resetall", "click", () => {\n  api("/api/reset", {target: "all"}).then(d => {\n    renderBlocks({blocks: [{kind: "ok", text: d.message || "Restored."}]});\n    loadSide();\n  });\n});\n\n/* ---------- drills (shared session plumbing) ---------- */\nlet S = null;   // {sid, mode, q, answered, area}\nfunction progressHTML(q) {\n  const pct = Math.round(100 * (q.index - 1) / q.total);\n  return \'<div class="qhead"><span class="tag">\' + esc(q.tag) + "</span>" +\n    \'<span class="qcount">Question \' + q.index + " of " + q.total +\n    \'</span></div><div class="bar"><i style="width:\' + pct + \'%"></i></div>\';\n}\nfunction startDrill(mode) {\n  const n = mode === "mcq" ? $("#qn").value : $("#sn").value;\n  const topic = mode === "mcq" ? $("#qtopic").value : "";\n  api("/api/quiz/start", {mode:mode, n:+n, topic:topic}).then(d => {\n    if (d.error) { alert(d.error); return; }\n    S = {sid:d.session, mode:d.mode, area: mode === "mcq" ? "#quizarea" : "#sqlarea"};\n    $(mode === "mcq" ? "#drillsetup" : "#ssetup").classList.add("hidden");\n    $(S.area).classList.remove("hidden");\n    renderQuestion(d.question);\n  });\n}\nbindEl("#qstart", "click", () => startDrill("mcq"));\nbindEl("#sstart", "click", () => startDrill("sql"));\n\nfunction renderQuestion(q) {\n  S.q = q; S.answered = false;\n  const el = $(S.area);\n  let h = progressHTML(q) +\n    \'<p class="qprompt">\' + esc(q.prompt) + "</p>";\n  if (q.qtype === "mcq") {\n    h += \'<div class="opts">\' + q.options.map((o, i) =>\n      \'<button class="opt" data-i="\' + i + \'"><b>\' +\n      "ABCDE"[i] + "</b><span>" + esc(o) + "</span></button>").join("") +\n      "</div>";\n    h += \'<div class="row" style="margin-top:14px">\' +\n      \'<button class="btn ghost" id="skipbtn">Skip</button>\' +\n      \'<span class="sub" style="margin:0">keys <kbd>A</kbd>&ndash;<kbd>\' +\n      "ABCDE"[q.options.length - 1] + "</kbd></span></div>";\n  } else {\n    h += \'<p class="dbline">database: <b>\' + esc(q.db) + "</b> &middot; tables: " +\n      q.tables.map(esc).join(", ") + "</p>" +\n      \'<textarea id="anssql" class="editor" spellcheck="false" \' +\n      \'placeholder="-- write your statement(s), then Submit"></textarea>\' +\n      \'<div class="row" style="margin-top:12px">\' +\n      \'<button class="btn gold" id="submitbtn">Submit</button>\' +\n      (q.has_hint ? \'<button class="btn ghost" id="hintbtn">Show hint</button>\' : "") +\n      \'<button class="btn ghost" id="skipbtn">Skip</button>\' +\n      \'<span class="sub" style="margin:0"><kbd>Ctrl</kbd>+<kbd>Enter</kbd> submits</span></div>\' +\n      \'<div id="hintbox"></div>\';\n  }\n  h += \'<div id="reveal"></div>\';\n  el.innerHTML = h;\n  if (q.qtype === "mcq") {\n    $$(".opt", el).forEach(b => b.addEventListener("click",\n      () => answer(+b.dataset.i)));\n  } else {\n    $("#submitbtn").addEventListener("click",\n      () => answer($("#anssql").value));\n    const hb = $("#hintbtn");\n    if (hb) hb.addEventListener("click", () =>\n      api("/api/quiz/answer", {session:S.sid, action:"hint"}).then(d =>\n        $("#hintbox").innerHTML = \'<div class="note">\' + esc(d.hint) + "</div>"));\n    $("#anssql").addEventListener("keydown", e => {\n      if ((e.ctrlKey || e.metaKey) && e.key === "Enter") {\n        e.preventDefault(); answer($("#anssql").value);\n      }\n    });\n    $("#anssql").focus();\n  }\n  $("#skipbtn").addEventListener("click", () => answer(null, true));\n}\nfunction answer(a, skip) {\n  if (!S || S.answered) return;\n  S.answered = true;\n  const body = {session: S.sid};\n  if (skip) body.action = "skip"; else body.answer = a;\n  api("/api/quiz/answer", body).then(d => {\n    if (d.error) { $(S.area).innerHTML =\n      \'<div class="errmsg">\' + esc(d.error) + "</div>"; return; }\n    revealAnswer(d, a, skip);\n  });\n}\nfunction revealAnswer(d, a, skip) {\n  const el = $(S.area);\n  let h = "";\n  const verdict = skip ? \'<div class="verdict no">Skipped</div>\' :\n    (d.correct ? \'<div class="verdict ok">&#10004; Correct</div>\'\n               : \'<div class="verdict no">&#10008; Not quite</div>\');\n  if (S.q.qtype === "mcq") {\n    $$(".opt", el).forEach(b => {\n      b.disabled = true;\n      const i = +b.dataset.i;\n      if (i === d.correct_index) b.classList.add("right");\n      else if (!skip && i === a) b.classList.add("wrong");\n    });\n    const sk = $("#skipbtn"); if (sk) sk.disabled = true;\n    h = verdict + \'<div class="explain">\' + esc(d.explain) + "</div>";\n  } else {\n    $("#submitbtn") && ($("#submitbtn").disabled = true);\n    $("#skipbtn") && ($("#skipbtn").disabled = true);\n    h = verdict;\n    (d.feedback || []).forEach(f => h += \'<ul class="fbl"><li>\' +\n      esc(f) + "</li></ul>");\n    h += \'<div class="sub" style="margin:12px 0 0">Reference solution</div>\' +\n      \'<pre class="refsql">\' + esc(d.reference) + "</pre>";\n    if (d.expected) h += \'<div class="sub" style="margin:12px 0 6px">\' +\n      "Expected result</div>" +\n      tableHTML(d.expected.headers, d.expected.rows, d.expected.total, false);\n  }\n  h += \'<div class="row" style="margin-top:16px">\' +\n    \'<button class="btn gold" id="nextbtn">\' +\n    (d.next ? "Next question" : "See summary") + "</button>" +\n    \'<span class="sub" style="margin:0"><kbd>Enter</kbd></span></div>\';\n  $("#reveal").innerHTML = h;\n  $("#nextbtn").addEventListener("click", () =>\n    d.next ? renderQuestion(d.next) : renderSummary(d.summary));\n  $("#nextbtn").focus();\n}\nfunction renderSummary(s) {\n  const cls = s.pct >= 80 ? "ok" : "no";\n  let h = \'<div class="qhead"><span class="tag">Session summary</span></div>\' +\n    \'<div class="bigscore">\' + s.score + "<small> / " + s.total +\n    " &middot; " + s.pct + "%</small></div>" +\n    \'<div style="margin:16px 0 6px" class="sub">By chapter</div>\';\n  s.chapters.forEach(c => {\n    const pct = Math.round(100 * c.correct / c.attempts);\n    h += \'<div class="chbar gold"><span>Ch\' + c.ch + "</span>" +\n      \'<span class="track"><i style="width:\' + pct + \'%"></i></span>\' +\n      "<span>" + c.correct + " / " + c.attempts + "</span></div>";\n  });\n  if (s.weak.length) {\n    h += \'<div class="weakrow sub">Review next: \' + s.weak.map(w =>\n      esc(w.name) + " (&sect;" + esc(w.ref) + ")").join("; ") +\n      " &mdash; now weighted more heavily.</div>";\n  } else {\n    h += \'<div class="weakrow sub">Clean sweep &mdash; these concepts will \' +\n      "show up a little less often now.</div>";\n  }\n  h += \'<div class="row" style="margin-top:16px">\' +\n    \'<button class="btn gold" id="againbtn">New drill</button>\';\n  if (S.mode === "mcq" && s.weak.length)\n    h += \'<button class="btn ghost" id="weakbtn">Drill weakest: \' +\n      esc(s.weak[0].name) + "</button>";\n  h += "</div>";\n  $(S.area).innerHTML = h;\n  $("#againbtn").addEventListener("click", () => {\n    $(S.area).classList.add("hidden");\n    $(S.mode === "mcq" ? "#drillsetup" : "#ssetup").classList.remove("hidden");\n    S = null;\n  });\n  const wb = $("#weakbtn");\n  if (wb) wb.addEventListener("click", () => {\n    api("/api/quiz/start", {mode:"mcq", n:8,\n        topic: s.weak[0].name.toLowerCase()}).then(d => {\n      if (d.error) { alert(d.error); return; }\n      S = {sid:d.session, mode:"mcq", area:"#quizarea"};\n      renderQuestion(d.question);\n    });\n  });\n}\ndocument.addEventListener("keydown", e => {\n  if (!S || e.target.tagName === "TEXTAREA" || e.target.tagName === "INPUT" ||\n      e.target.tagName === "SELECT") return;\n  if (!S.answered && S.q && S.q.qtype === "mcq") {\n    const i = "abcde".indexOf(e.key.toLowerCase());\n    const j = "12345".indexOf(e.key);\n    const k = i >= 0 ? i : j;\n    if (k >= 0 && k < S.q.options.length) {\n      e.preventDefault();\n      const b = $(S.area + \' .opt[data-i="\' + k + \'"]\');\n      if (b && !b.disabled) b.click();\n    }\n  }\n});\n\n/* ---------- mastery ---------- */\nasync function loadMastery() {\n  const d = await api("/api/stats");\n  const box = $("#masterybody");\n  if (!d.concepts.length) {\n    box.innerHTML = \'<div class="empty">No drills yet &mdash; your mastery \' +\n      "map fills in as you answer. Start with an exam drill.</div>";\n    return;\n  }\n  let h = "";\n  let ch = null;\n  d.concepts.forEach(r => {\n    if (r.ch !== ch) { ch = r.ch;\n      h += \'<div class="mgroup">CHAPTER \' + ch + "</div>"; }\n    h += \'<div class="mrow"><span class="ref">&sect;\' + esc(r.ref) + "</span>" +\n      "<span>" + esc(r.name) + "</span>" +\n      \'<span class="track"><i style="width:\' + r.pct + \'%"></i></span>\' +\n      \'<span class="pct">\' + r.correct + "/" + r.attempts + "</span></div>";\n  });\n  if (d.weak.length)\n    h += \'<div class="weakrow sub">Weakest right now: \' + d.weak.map(w =>\n      esc(w.name) + " (&sect;" + esc(w.ref) + ")").join("; ") + "</div>";\n  h += \'<div class="weakrow sub">OA blueprint baseline: \' + d.blueprint.map(b =>\n    "Ch" + b.ch + " " + b.w + "%").join(" &middot; ") + "</div>";\n  box.innerHTML = h;\n}\nbindEl("#mreload", "click", loadMastery);\nbindEl("#mreset", "click", () => {\n  if (confirm("Reset all drill history?"))\n    api("/api/stats/reset", {}).then(loadMastery);\n});\n\n/* ---------- boot ---------- */\nloadSide();\nconst want = location.hash.replace("#", "");\nconst avail = $$(".tab").map(b => b.dataset.tab);\nopenTab(avail.includes(want) ? want : avail[0]);\n</script>\n</body></html>'

PLAYGROUND_SECTION = '<section id="playground">\n  <div class="play">\n    <aside class="panel dbpane" id="sidepane">\n      <h3 id="sidetitle"></h3>\n      <p class="sub" id="sidesub"></p>\n      <div id="sidelist"></div>\n      <p style="margin:12px 0 0"><button class="linkish hidden" id="resetall"></button></p>\n    </aside>\n    <div>\n      <div class="panel">\n        <div class="row" style="justify-content:space-between">\n          <h3 style="margin:0">%%PG_LABEL%%</h3>\n          <div class="row">\n            <label class="sub hidden" style="margin:0" for="pgsel" id="pgsellbl"></label>\n            <select id="pgsel" class="hidden"></select>\n            <button class="btn gold" id="runbtn">Run</button>\n            <span class="sub" style="margin:0"><kbd>Ctrl</kbd>+<kbd>Enter</kbd></span>\n          </div>\n        </div>\n        <textarea id="pgbox" class="editor" spellcheck="false" placeholder="%%PG_PLACEHOLDER%%"></textarea>\n        <div id="stdinwrap" class="%%PG_STDIN_CLASS%%">\n          <label class="sub" for="pgstdin" style="display:block;margin:10px 0 4px">program input (stdin)</label>\n          <textarea id="pgstdin" class="editor stdin" spellcheck="false"></textarea>\n        </div>\n      </div>\n      <div id="results"></div>\n    </div>\n  </div>\n</section>\n'

SQLDRILL_SECTION = '<section id="sqldrill" class="hidden">\n  <div class="panel" id="ssetup">\n    <h3>SQL drill</h3>\n    <p class="sub">Write real statements against fresh copies of the course data.\n      Graded by running your SQL and comparing results &mdash; messy-but-correct passes.</p>\n    <div class="row">\n      <label class="sub" style="margin:0" for="sn">tasks</label>\n      <select id="sn"><option>3</option><option selected>5</option>\n        <option>8</option><option>10</option><option>15</option></select>\n      <button class="btn gold" id="sstart">Start drill</button>\n    </div>\n  </div>\n  <div class="panel hidden" id="sqlarea"></div>\n</section>'

HOME_TMPL = '<!doctype html>\n<html lang="en"><head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width,initial-scale=1">\n<title>WGU Study Hub</title>\n<link rel="icon" href="%%FAVICON%%">\n<link rel="stylesheet" href="/app.css">\n</head><body>\n<header class="topbar"><div class="wrap">\n  <a class="brand" href="/">%%OWL%% WGU Study Hub</a>\n  <span class="spacer"></span>\n  <span class="badge-cli">LOCAL &middot; PRIVATE &middot; OFFLINE</span>\n</div></header>\n\n<section class="hero"><div class="wrap">\n  <div>\n    <span class="eyebrow">Night-owl study hub</span>\n    <h1>Pick a course.<br>Start drilling.</h1>\n    <p>Your personal study tools, running entirely on this machine.\n       Playgrounds use each course\'s own lab data; drills are weighted the\n       way the real assessments are.</p>\n  </div>\n  %%OWL%%\n</div></section>\n\n<main class="wrap">\n  <div class="cards">\n%%CARDS%%\n  </div>\n  <p class="foot">Unofficial personal study tool &mdash; not affiliated with\n  or endorsed by Western Governors University. Progress is stored locally in\n  <span class="mono">~/.d426_sandbox</span> and is shared with the terminal\n  version.</p>\n</main>\n</body></html>'

APP_CSS = "\n:root{\n  --navy:#003057; --navy2:#0A3B66; --night:#001B33; --night2:#000F1F;\n  --gold:#FFB81C; --gold-dk:#B87E00; --sky:#8FBCE8; --blue:#0B6BC2;\n  --paper:#F3F6FA; --card:#FFFFFF; --ink:#17293B; --mut:#5B7186;\n  --line:#D9E3EE; --ok:#1E8A5A; --okbg:#E9F6EF; --bad:#C0392B; --badbg:#FBECEA;\n  --console:#07223B; --constext:#DCE9F5;\n  --mono:ui-monospace,'Cascadia Code','JetBrains Mono',Menlo,Consolas,monospace;\n  --sans:system-ui,-apple-system,'Segoe UI',Roboto,'Helvetica Neue',Arial,sans-serif;\n}\n*{box-sizing:border-box}\nhtml,body{margin:0;padding:0}\nbody{font:15px/1.55 var(--sans);color:var(--ink);background:var(--paper)}\na{color:var(--blue)}\n:focus-visible{outline:3px solid var(--gold);outline-offset:2px;border-radius:4px}\n.mono{font-family:var(--mono)}\n.eyebrow{font:600 11px/1 var(--mono);letter-spacing:.18em;text-transform:uppercase;color:var(--gold)}\n.wrap{max-width:1180px;margin:0 auto;padding:0 20px}\n\n/* top bar */\n.topbar{background:var(--navy);color:#fff}\n.topbar .wrap{display:flex;align-items:center;gap:14px;min-height:54px}\n.brand{display:flex;align-items:center;gap:10px;color:#fff;text-decoration:none;font-weight:700}\n.brand .owl{width:26px;height:27px}\n.crumb{color:var(--sky);font-family:var(--mono);font-size:13px}\n.topbar .spacer{flex:1}\n.badge-cli{font:600 10px/1 var(--mono);letter-spacing:.12em;color:var(--sky);\n  border:1px solid #1C5586;border-radius:99px;padding:5px 9px}\n\n/* hub hero */\n.hero{background:\n  radial-gradient(1.6px 1.6px at 12% 30%, #7FB2E566 50%, transparent 51%),\n  radial-gradient(1.4px 1.4px at 78% 22%, #FFB81C55 50%, transparent 51%),\n  radial-gradient(1.6px 1.6px at 62% 68%, #7FB2E54D 50%, transparent 51%),\n  radial-gradient(1.2px 1.2px at 34% 78%, #FFFFFF40 50%, transparent 51%),\n  radial-gradient(1.6px 1.6px at 90% 62%, #7FB2E540 50%, transparent 51%),\n  linear-gradient(160deg, var(--navy) 0%, var(--night) 62%, var(--night2) 100%);\n  color:#fff}\n.hero .wrap{display:grid;grid-template-columns:1fr 200px;gap:24px;\n  align-items:center;padding:52px 20px 46px}\n.hero h1{font-size:36px;line-height:1.15;letter-spacing:-.01em;margin:12px 0 10px}\n.hero p{color:var(--sky);max-width:52ch;margin:0}\n.hero .owl{width:180px;height:189px;justify-self:end;filter:drop-shadow(0 12px 26px #00000059)}\n.lid{transform:scaleY(0);transform-box:fill-box;transform-origin:center;\n  animation:blink 6.5s infinite}\n@keyframes blink{0%,91%,100%{transform:scaleY(0)}93.5%,96.5%{transform:scaleY(1)}}\n\n/* course cards */\n.cards{display:grid;grid-template-columns:repeat(auto-fill,minmax(330px,1fr));\n  gap:18px;padding:30px 0 44px}\n.course{display:block;background:var(--card);border:1px solid var(--line);\n  border-radius:14px;padding:22px;text-decoration:none;color:var(--ink);\n  transition:transform .14s ease, box-shadow .14s ease;position:relative}\na.course:hover{transform:translateY(-3px);box-shadow:0 12px 26px #00305726}\n.course .code{font:700 30px/1 var(--mono);color:var(--navy);letter-spacing:.01em}\n.course .code b{color:var(--gold-dk)}\n.course h2{font-size:17px;margin:8px 0 6px}\n.course p{color:var(--mut);font-size:13.5px;margin:0 0 14px}\n.chiprow{display:flex;flex-wrap:wrap;gap:7px}\n.chip{font:600 11.5px/1 var(--mono);color:var(--navy);background:#EAF1F8;\n  border:1px solid var(--line);border-radius:99px;padding:6px 10px}\n.course.planned{opacity:.62;background:repeating-linear-gradient(-45deg,#fff,\n  #fff 12px,#F7FAFD 12px,#F7FAFD 24px)}\n.pill{position:absolute;top:16px;right:16px;font:700 10px/1 var(--mono);\n  letter-spacing:.14em;color:var(--navy);background:var(--gold);\n  border-radius:99px;padding:5px 9px}\n.pill.dim{background:#E3EAF2;color:var(--mut)}\n.foot{color:var(--mut);font-size:12.5px;padding:0 0 34px}\n\n/* tabs */\n.tabs{background:var(--navy)}\n.tabs .wrap{display:flex;gap:4px}\n.tab{appearance:none;background:none;border:0;color:var(--sky);cursor:pointer;\n  font:600 13.5px/1 var(--sans);padding:13px 14px 11px;border-bottom:3px solid transparent}\n.tab:hover{color:#fff}\n.tab.on{color:#fff;border-bottom-color:var(--gold)}\n\n/* panels + generic */\nmain.wrap{padding:22px 20px 60px}\n.panel{background:var(--card);border:1px solid var(--line);border-radius:12px;\n  padding:18px}\n.panel h3{margin:0 0 4px;font-size:16px}\n.sub{color:var(--mut);font-size:13px;margin:0 0 12px}\n.row{display:flex;gap:10px;align-items:center;flex-wrap:wrap}\n.btn{appearance:none;border:1px solid var(--navy);background:var(--navy);\n  color:#fff;font:600 13.5px/1 var(--sans);border-radius:9px;padding:10px 15px;\n  cursor:pointer}\n.btn:hover{background:#0A4472}\n.btn.gold{background:var(--gold);border-color:var(--gold);color:var(--navy)}\n.btn.gold:hover{background:#FFC749}\n.btn.ghost{background:#fff;color:var(--navy);border-color:var(--line)}\n.btn.ghost:hover{border-color:var(--navy)}\n.btn:disabled{opacity:.45;cursor:default}\nselect,input[type=text]{font:14px var(--sans);color:var(--ink);\n  border:1px solid var(--line);border-radius:9px;padding:9px 10px;background:#fff}\nkbd{font:600 11px var(--mono);color:var(--mut);border:1px solid var(--line);\n  border-bottom-width:2px;border-radius:5px;padding:2px 5px;background:#fff}\n\n/* playground layout */\n.play{display:grid;grid-template-columns:262px 1fr;gap:18px;align-items:start}\n.dbpane .dbgroup{padding:10px 0;border-bottom:1px solid var(--line)}\n.dbpane .dbgroup:last-child{border-bottom:0}\n.dbname{display:flex;align-items:center;gap:8px;font:700 13px var(--mono);\n  color:var(--navy)}\n.dot{width:8px;height:8px;border-radius:99px;background:var(--line)}\n.dot.on{background:var(--gold)}\n.dbdesc{color:var(--mut);font-size:11.5px;margin:3px 0 8px}\n.tchips{display:flex;flex-wrap:wrap;gap:6px}\n.tchip{display:inline-flex;align-items:center;gap:0;border:1px solid var(--line);\n  border-radius:8px;overflow:hidden;background:#fff}\n.tchip button{appearance:none;border:0;background:none;cursor:pointer;\n  font:600 12px var(--mono);color:var(--ink);padding:6px 8px}\n.tchip button:hover{background:#EFF5FB}\n.tchip .sch{border-left:1px solid var(--line);color:var(--mut);font-size:11px}\n.linkish{appearance:none;border:0;background:none;color:var(--blue);\n  cursor:pointer;font:12.5px var(--sans);padding:0;text-decoration:underline}\n.editor{width:100%;min-height:132px;resize:vertical;background:var(--console);\n  color:var(--constext);caret-color:var(--gold);border:1px solid #0F3B61;\n  border-radius:10px;font:13.5px/1.6 var(--mono);padding:13px 14px}\n.editor::placeholder{color:#6C8FAE}\n\n/* results */\n.result{margin-top:14px}\n.tablewrap{overflow:auto;border:1px solid var(--line);border-radius:10px}\ntable.res{border-collapse:collapse;width:100%;font:12.8px var(--mono);background:#fff}\ntable.res th{position:sticky;top:0;background:#EAF1F8;color:var(--navy);\n  text-align:left;padding:8px 11px;border-bottom:2px solid var(--line);white-space:nowrap}\ntable.res td{padding:7px 11px;border-bottom:1px solid #EDF2F8;white-space:nowrap}\ntable.res tr:nth-child(even) td{background:#FAFCFE}\ntd .null{color:#9AACBE;font-style:italic}\n.meta{color:var(--mut);font:12px var(--mono);margin:7px 2px 0}\n.okmsg{background:var(--okbg);border-left:4px solid var(--ok);border-radius:8px;\n  padding:9px 12px;font:13px var(--mono);color:#14563B}\n.errmsg{background:var(--badbg);border-left:4px solid var(--bad);border-radius:8px;\n  padding:9px 12px;font:13px var(--mono);color:#7C2A21}\n.note{background:#FFF7E4;border-left:4px solid var(--gold);border-radius:8px;\n  padding:8px 12px;font:12.5px var(--sans);color:#6B5410;margin-top:8px}\n\n/* drills */\n.qhead{display:flex;justify-content:space-between;align-items:center;gap:12px}\n.qcount{font:700 13px var(--mono);color:var(--mut)}\n.bar{height:6px;background:#E7EDF4;border-radius:99px;overflow:hidden;margin:10px 0 16px}\n.bar i{display:block;height:100%;width:0;background:var(--gold);transition:width .25s}\n.tag{display:inline-block;font:600 11px var(--mono);letter-spacing:.05em;\n  color:var(--navy);background:#EAF1F8;border:1px solid var(--line);\n  border-radius:99px;padding:5px 10px;margin-bottom:10px}\n.qprompt{font-size:16.5px;line-height:1.5;margin:0 0 14px;white-space:pre-wrap}\n.opts{display:grid;gap:9px}\n.opt{appearance:none;text-align:left;border:1.5px solid var(--line);\n  background:#fff;border-radius:10px;padding:12px 14px;font:14px/1.45 var(--sans);\n  color:var(--ink);cursor:pointer;display:flex;gap:10px}\n.opt:hover:not(:disabled){border-color:var(--navy)}\n.opt b{font-family:var(--mono);color:var(--mut);min-width:16px}\n.opt.right{border-color:var(--ok);background:var(--okbg)}\n.opt.right b{color:var(--ok)}\n.opt.wrong{border-color:var(--bad);background:var(--badbg)}\n.opt.wrong b{color:var(--bad)}\n.opt:disabled{cursor:default}\n.verdict{font:700 14px var(--sans);margin:14px 0 4px}\n.verdict.ok{color:var(--ok)}.verdict.no{color:var(--bad)}\n.explain{background:#F2F6FB;border-left:4px solid var(--navy);border-radius:8px;\n  padding:10px 13px;font-size:13.5px;color:#2C4258}\n.refsql{background:var(--console);color:var(--constext);border-radius:10px;\n  padding:12px 14px;font:13px/1.6 var(--mono);overflow:auto;margin:10px 0 0;\n  white-space:pre-wrap}\n.fbl{margin:10px 0 0;padding-left:20px;color:#7C2A21;font-size:13.5px}\n.dbline{font:12.5px var(--mono);color:var(--mut);margin:0 0 10px}\n\n/* summary + mastery */\n.bigscore{font:700 44px/1 var(--mono);color:var(--navy)}\n.bigscore small{font-size:18px;color:var(--mut)}\n.chbar{display:grid;grid-template-columns:52px 1fr 62px;gap:10px;\n  align-items:center;margin:7px 0;font:12.5px var(--mono)}\n.chbar .track{height:9px;background:#E7EDF4;border-radius:99px;overflow:hidden}\n.chbar .track i{display:block;height:100%;background:var(--navy)}\n.chbar.gold .track i{background:var(--gold)}\n.weakrow{margin-top:14px}\n.mgroup{margin:16px 0 4px;font:700 13px var(--mono);color:var(--navy);\n  letter-spacing:.06em}\n.mrow{display:grid;grid-template-columns:86px 1fr 150px 52px;gap:12px;\n  align-items:center;padding:7px 0;border-bottom:1px solid #EDF2F8;font-size:13.5px}\n.mrow .ref{font:600 12px var(--mono);color:var(--mut)}\n.mrow .track{height:8px;background:#E7EDF4;border-radius:99px;overflow:hidden}\n.mrow .track i{display:block;height:100%;background:var(--gold)}\n.mrow .pct{font:700 12.5px var(--mono);text-align:right}\n.empty{color:var(--mut);padding:26px 6px;text-align:center}\n.hidden{display:none}\n\n@media (max-width:920px){\n  .play{grid-template-columns:1fr}\n  .hero .wrap{grid-template-columns:1fr;padding:38px 20px}\n  .hero .owl{display:none}\n  .mrow{grid-template-columns:70px 1fr 90px 46px}\n}\n@media (prefers-reduced-motion:reduce){\n  .lid{animation:none}\n  a.course:hover{transform:none}\n}\n\n.editor.stdin{min-height:56px;height:56px}\n.play.noside{grid-template-columns:1fr;display:block}\n.pgout{white-space:pre-wrap;margin:0;font-family:var(--mono,monospace);font-size:13px}\n"

OWL_SVG = '\n<svg class="owl" viewBox="0 0 120 126" aria-hidden="true">\n  <path d="M30 36 L40 14 L50 33 Z" fill="#0A3B66"/>\n  <path d="M90 36 L80 14 L70 33 Z" fill="#0A3B66"/>\n  <ellipse cx="60" cy="74" rx="40" ry="46" fill="#0A3B66"/>\n  <ellipse cx="60" cy="60" rx="35" ry="31" fill="#0E4A7B"/>\n  <ellipse cx="60" cy="98" rx="21" ry="15" fill="#12588F"/>\n  <circle cx="45" cy="58" r="14" fill="#FFB81C"/>\n  <circle cx="75" cy="58" r="14" fill="#FFB81C"/>\n  <circle cx="45" cy="58" r="6" fill="#001527"/>\n  <circle cx="75" cy="58" r="6" fill="#001527"/>\n  <rect class="lid" x="31" y="44" width="28" height="28" rx="14" fill="#0E4A7B"/>\n  <rect class="lid" x="61" y="44" width="28" height="28" rx="14" fill="#0E4A7B"/>\n  <path d="M60 66 L53 75 L60 85 L67 75 Z" fill="#FFB81C"/>\n</svg>'

FAVICON = "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 32 32'%3E%3Crect width='32' height='32' rx='7' fill='%23003057'/%3E%3Ccircle cx='11' cy='13' r='6' fill='%23FFB81C'/%3E%3Ccircle cx='21' cy='13' r='6' fill='%23FFB81C'/%3E%3Ccircle cx='11' cy='13' r='2.6' fill='%23001527'/%3E%3Ccircle cx='21' cy='13' r='2.6' fill='%23001527'/%3E%3Cpath d='M16 16l-3.2 4.2 3.2 4.2 3.2-4.2z' fill='%23FFB81C'/%3E%3C/svg%3E"

